#include <stdio.h>
#include <omp.h>

void
findK(long height,
      knode *knodesD,
      long knodes_elem,
      record *recordsD,

      long *currKnodeD,
      long *offsetD,
      int *keysD,
      record *ansD,
      int order,
      int count)
{
    // For each block = count, parallelize over blocks
#pragma omp parallel for
    for (int bid = 0; bid < count; bid++) {
        // For each thread = order, parallelize over keys inside block
        for (int i = 0; i < height; i++) {
            long currKnode = currKnodeD[bid];
            long offset = offsetD[bid];
            // We do a loop over thid
            // We must emulate the original kernel where threads within a block cooperate
            // Here we do it sequentially for correctness
            // Alternatively, parallelize over thid with synchronization via omp barrier

            // To parallelize over thid safely with synchronization, use omp parallel for with ordered or critical sections
            // Because we need to update offsetD[bid] only if condition is met and only one thread updates it at a time
            // We'll do a parallel loop over thid with atomic update of offsetD[bid]

            int updated_offset = offset;
#pragma omp parallel for
            for (int thid = 0; thid < order; thid++) {
                int key_thid = knodesD[currKnode].keys[thid];
                int key_thid1 = knodesD[currKnode].keys[thid + 1];
                if ((key_thid <= keysD[bid]) && (key_thid1 > keysD[bid])) {
                    if (knodesD[offset].indices[thid] < knodes_elem) {
#pragma omp critical
                        {
                            if (knodesD[offset].indices[thid] < updated_offset || updated_offset == offset)
                                updated_offset = knodesD[offset].indices[thid];
                        }
                    }
                }
            }
            offsetD[bid] = updated_offset;
            currKnodeD[bid] = offsetD[bid];
        }

        long currKnode = currKnodeD[bid];
        int key_bid = keysD[bid];
        // Now assign ansD[bid].value if keys match
#pragma omp parallel for
        for (int thid = 0; thid < order; thid++) {
            if (knodesD[currKnode].keys[thid] == key_bid) {
                ansD[bid].value = recordsD[knodesD[currKnode].indices[thid]].value;
            }
        }
    }
}

