#include <stdio.h>
#include <omp.h>

void
findRangeK(long height,

           knode *knodesD,
           long knodes_elem,

           long *currKnodeD,
           long *offsetD,
           long *lastKnodeD,
           long *offset_2D,
           int *startD,
           int *endD,
           int *RecstartD,
           int *ReclenD,
           int order,
           int count)
{
#pragma omp parallel for
    for (int bid = 0; bid < count; bid++) {
        for (int i = 0; i < height; i++) {
            long currKnode = currKnodeD[bid];
            long lastKnode = lastKnodeD[bid];
            long offset = offsetD[bid];
            long offset_2 = offset_2D[bid];

#pragma omp parallel for
            for (int thid = 0; thid < order; thid++) {
                int curr_key = knodesD[currKnode].keys[thid];
                int curr_key1 = knodesD[currKnode].keys[thid + 1];
                int last_key = knodesD[lastKnode].keys[thid];
                int last_key1 = knodesD[lastKnode].keys[thid + 1];

                if ((curr_key <= startD[bid]) && (curr_key1 > startD[bid])) {
                    if (knodesD[currKnode].indices[thid] < knodes_elem) {
#pragma omp critical
                        {
                            if (knodesD[currKnode].indices[thid] < offset || offset == offsetD[bid])
                                offset = knodesD[currKnode].indices[thid];
                        }
                    }
                }
                if ((last_key <= endD[bid]) && (last_key1 > endD[bid])) {
                    if (knodesD[lastKnode].indices[thid] < knodes_elem) {
#pragma omp critical
                        {
                            if (knodesD[lastKnode].indices[thid] < offset_2 || offset_2 == offset_2D[bid])
                                offset_2 = knodesD[lastKnode].indices[thid];
                        }
                    }
                }
            }
            offsetD[bid] = offset;
            offset_2D[bid] = offset_2;
            currKnodeD[bid] = offsetD[bid];
            lastKnodeD[bid] = offset_2D[bid];
        }

        long currKnode = currKnodeD[bid];
        long lastKnode = lastKnodeD[bid];
        int start_key = startD[bid];
        int end_key = endD[bid];

#pragma omp parallel for
        for (int thid = 0; thid < order; thid++) {
            if (knodesD[currKnode].keys[thid] == start_key) {
                RecstartD[bid] = knodesD[currKnode].indices[thid];
            }
        }

#pragma omp parallel for
        for (int thid = 0; thid < order; thid++) {
            if (knodesD[lastKnode].keys[thid] == end_key) {
                ReclenD[bid] = knodesD[lastKnode].indices[thid] - RecstartD[bid] + 1;
            }
        }
    }
}
